#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e5+5;
const int up = 5000000;
int T,n,a[N],ans;
int cnt,p[N],mx[up+5],res[up+5];
bool vis[up+5];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(){
    vis[1]=1,mx[1]=1,res[1]=1;
    for(int i=2;i<=up;i++){
        if(!vis[i])p[++cnt]=i,mx[i%4]=i;
        for(int j=1;j<=cnt&&i*p[j]<=up;j++){
            vis[i*p[j]]=1;
            if(i%p[j]==0)break;
        }if(i%4!=0)res[i]=(i-mx[i%4])/2+1;
        else res[i]=i/2;
    }return;
}
int main(){
    T=read();init();
    while(T--){
        n=read(),ans=up+5;
        for(int i=1;i<=n;i++){
            a[i]=read();
            if(ans/2>res[a[i]]/2)ans=res[a[i]];
        }if(ans&1)cout<<"Farmer John\n";
        else cout<<"Farmer Nhoj\n";
    }
    return 0;
}
